#include<bits/stdc++.h>
using namespace std;
constexpr long long inf=123456789123456789;
long long n,m;
vector<pair<long long,long long>> mp[100010];
long long dfn[100010],rnk[100010],val[100010];
long long d[100010],dis[100010],fa[100010],siz[100010],top[100010];
long long son[100010],dfncnt;
void dfs1(long long x,long long f=0)
{
    siz[x]=1;
    son[x]=-1;
    for(auto i:mp[x])
    {
        long long v=i.first,val=i.second;
        if(v!=f)
        {
            dis[v]=dis[x]+val;
            d[v]=d[x]+1;
            fa[v]=x;
            dfs1(v,x);
            siz[x]+=siz[v];
            if(son[x]==-1||siz[v]>siz[son[x]])
            {
                son[x]=v;
            }
        }
    }
}
void dfs2(long long x,long long t)
{
    top[x]=t;
    dfn[x]=++dfncnt;
    rnk[dfn[x]]=x;
    if(son[x]!=-1)
    {
        dfs2(son[x],t);
        for(auto i:mp[x])
        {
            long long v=i.first;
            if(v!=son[x]&&v!=fa[x])
            {
                dfs2(v,v);
            }
        }
    }
}
struct LiChaoTree
{
    long long cnt,min1[800010],k[800010],b[800010],t[800010];
    void build(long long x,long long l,long long r)
    {
        min1[x]=min1[x<<1]=min1[x<<1|1]=inf;
        t[x]=t[x<<1]=t[x<<1|1]=1;
        if(l==r)
        {
            return;
        }
        long long mid=(l+r)>>1;
        build(x<<1,l,mid);
        build(x<<1|1,mid+1,r);
    }
    void add(long long K,long long B)
    {
        k[++cnt]=K;
        b[cnt]=B;
    }
    long long calc(long long x,long long id)
    {
        return k[id]*dis[rnk[x]]+b[id];
    }
    void pushup(long long x)
    {
        min1[x]=min({min1[x],min1[x<<1],min1[x<<1|1]});
    }
    void update(long long x,long long l,long long r,long long u,long long v,long long p)
    {
        long long mid=(l+r)>>1;
        if(u<=l&&r<=v)
        {
            if(calc(l,p)<=calc(l,t[x])&&calc(r,p)<=calc(r,t[x]))
            {
                t[x]=p;
                min1[x]=min({min1[x],calc(l,p),calc(r,p)});
                return;
            }
            if(calc(l,p)>=calc(l,t[x])&&calc(r,p)>=calc(r,t[x]))
            {
                return;
            }
            if(k[p]<k[t[x]])
            {
                if(calc(mid,p)<=calc(mid,t[x]))
                {
                    update(x<<1,l,mid,u,v,t[x]);
                    t[x]=p;
                }
                else
                {
                    update(x<<1|1,mid+1,r,u,v,p);
                }
            }
            else
            {
                if(calc(mid,p)<=calc(mid,t[x]))
                {
                    update(x<<1|1,mid+1,r,u,v,t[x]);
                    t[x]=p;
                }
                else
                {
                    update(x<<1,l,mid,u,v,p);
                }
            }
            min1[x]=min({min1[x],calc(l,p),calc(r,p)});
            pushup(x);
            return;
        }
        if(u<=mid)
        {
            update(x<<1,l,mid,u,v,p);
        }
        if(v>mid)
        {
            update(x<<1|1,mid+1,r,u,v,p);
        }
        pushup(x);
    }
    long long query(long long x,long long l,long long r,long long u,long long v)
    {
        if(u<=l&&r<=v)
        {
            return min1[x];
        }
        long long mid=(l+r)>>1;
        long long ans=inf;
        if(b[t[x]]!=inf)
        {
            ans=min(calc(max(l,u),t[x]),calc(min(r,v),t[x]));
        }
        if(u<=mid)
        {
            ans=min(ans,query(x<<1,l,mid,u,v));
        }
        if(v>mid)
        {
            ans=min(ans,query(x<<1|1,mid+1,r,u,v));
        }
        return ans;
    }
}t;
long long lca(long long x,long long y)
{
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        return y;
    }
    return x;
}
long long query(long long x,long long y)
{
    long long ans=inf;
    while(top[x]!=top[y])
    {
        if(d[top[x]]<d[top[y]])
        {
            swap(x,y);
        }
        ans=min(ans,t.query(1,1,n,dfn[top[x]],dfn[x]));
        x=fa[top[x]];
    }
    if(d[x]>d[y])
    {
        swap(x,y);
    }
    ans=min(ans,t.query(1,1,n,dfn[x],dfn[y]));
    return ans;
}
void update(long long x,long long y)
{
    while(top[x]!=top[y])
    {
        t.update(1,1,n,dfn[top[x]],dfn[x],t.cnt);
        x=fa[top[x]];
    }
    t.update(1,1,n,dfn[y],dfn[x],t.cnt);
}
int main()
{
    scanf("%lld%lld",&n,&m);
    for(long long i=1;i<n;i++)
    {
        long long u,v,w;
        scanf("%lld%lld%lld",&u,&v,&w);
        mp[u].push_back({v,w});
        mp[v].push_back({u,w});
    }
    dfs1(1);
    dfs2(1,1);
    t.add(0,inf);
    t.build(1,1,n);
    while(m--)
    {
        long long op,s,t;
        scanf("%lld%lld%lld",&op,&s,&t);
        long long l=lca(s,t);
        if(op==1)
        {
            long long x,y;
            scanf("%lld%lld",&x,&y);
            ::t.add(-x,x*dis[s]+y);
            update(s,l);
            ::t.add(x,x*(dis[s]-dis[l]*2)+y);
            update(t,l);
        }
        else
        {
            printf("%lld\n",query(s,t));
        }
    }
    return 0;
}
